  1→import { useState, useRef, useEffect, useCallback } from 'react';
  2→import type { Project, GitHubRepo } from '../types';
  3→import { api } from '../api/client';
  4→
  5→type Tab = 'github' | 'local';
  6→type GitHubState = 'idle' | 'device_flow' | 'connected';
  7→
  8→interface ProjectSetupProps {
  9→  projects: Project[];
 10→  onSelect: (project: Project) => void;
 11→  onCreate: (name: string, path: string) => void;
 12→  onClone: (repoUrl: string) => Promise<void>;
 13→}
 14→
 15→export function ProjectSetup({ projects, onSelect, onCreate, onClone }: ProjectSetupProps) {
 16→  const [tab, setTab] = useState<Tab>('github');
 17→  const [name, setName] = useState('');
 18→  const [path, setPath] = useState('');
 19→  const [repoUrl, setRepoUrl] = useState('');
 20→  const [error, setError] = useState('');
 21→  const [cloning, setCloning] = useState(false);
 22→
 23→  // GitHub auth state
 24→  const [ghState, setGhState] = useState<GitHubState>('idle');
 25→  const [repos, setRepos] = useState<GitHubRepo[]>([]);
 26→  const [repoSearch, setRepoSearch] = useState('');
 27→  const [selectedRepo, setSelectedRepo] = useState<GitHubRepo | null>(null);
 28→  const [showManualInput, setShowManualInput] = useState(false);
 29→  const [tokenInput, setTokenInput] = useState('');
 30→  const [connectingToken, setConnectingToken] = useState(false);
 31→  const [clientIdConfigured, setClientIdConfigured] = useState(false);
 32→  const [showPatInput, setShowPatInput] = useState(false);
 33→
 34→  // Device flow state
 35→  const [deviceUserCode, setDeviceUserCode] = useState('');
 36→  const [deviceVerificationUri, setDeviceVerificationUri] = useState('');
 37→  const pollRef = useRef<ReturnType<typeof setInterval> | null>(null);
 38→
 39→  const repoRef = useRef<HTMLInputElement>(null);
 40→  const nameRef = useRef<HTMLInputElement>(null);
 41→  const tokenRef = useRef<HTMLInputElement>(null);
 42→
 43→  // Check GitHub auth status on mount
 44→  useEffect(() => {
 45→    api.githubStatus()
 46→      .then((s) => {
 47→        setClientIdConfigured(s.client_id_configured);
 48→        if (s.connected) {
 49→          setGhState('connected');
 50→          api.githubRepos().then(setRepos).catch(console.error);
 51→        }
 52→      })
 53→      .catch(console.error);
 54→  }, []);
 55→
 56→  // Cleanup device flow polling on unmount
 57→  useEffect(() => {
 58→    return () => {
 59→      if (pollRef.current) clearInterval(pollRef.current);
 60→    };
 61→  }, []);
 62→
 63→  useEffect(() => {
 64→    if (tab === 'github' && showManualInput) repoRef.current?.focus();
 65→    else if (tab === 'github' && ghState === 'idle') tokenRef.current?.focus();
 66→    else if (tab === 'local') nameRef.current?.focus();
 67→  }, [tab, showManualInput, ghState]);
 68→
 69→  const handleConnectToken = useCallback(async (e: React.FormEvent) => {
 70→    e.preventDefault();
 71→    if (!tokenInput.trim()) return;
 72→    setError('');
 73→    setConnectingToken(true);
 74→    try {
 75→      await api.githubConnectToken(tokenInput.trim());
 76→      setGhState('connected');
 77→      setTokenInput('');
 78→      const fetchedRepos = await api.githubRepos();
 79→      setRepos(fetchedRepos);
 80→    } catch (err) {
 81→      setError(err instanceof Error ? err.message : 'Failed to connect');
 82→    } finally {
 83→      setConnectingToken(false);
 84→    }
 85→  }, [tokenInput]);
 86→
 87→  const handleDeviceFlow = useCallback(async () => {
 88→    setError('');
