 90→      const result = await api.githubDeviceCode();
 91→      setDeviceUserCode(result.user_code);
 92→      setDeviceVerificationUri(result.verification_uri);
 93→      setGhState('device_flow');
 94→
 95→      // Start polling for token completion
 96→      const interval = Math.max(result.interval, 5) * 1000;
 97→      pollRef.current = setInterval(async () => {
 98→        try {
 99→          const poll = await api.githubPollToken(result.device_code);
100→          if (poll.status === 'complete') {
101→            if (pollRef.current) clearInterval(pollRef.current);
102→            pollRef.current = null;
103→            setGhState('connected');
104→            setDeviceUserCode('');
105→            setDeviceVerificationUri('');
106→            const fetchedRepos = await api.githubRepos();
107→            setRepos(fetchedRepos);
108→          }
109→        } catch (err) {
110→          const msg = err instanceof Error ? err.message : String(err);
111→          if (msg.includes('access_denied') || msg.includes('expired_token')) {
112→            if (pollRef.current) { clearInterval(pollRef.current); pollRef.current = null; }
113→            setGhState('idle');
114→            setDeviceUserCode('');
115→            setDeviceVerificationUri('');
116→          }
117→          // authorization_pending and slow_down are expected -- continue polling
118→        }
119→      }, interval);
120→    } catch (err) {
121→      setError(err instanceof Error ? err.message : 'Failed to start device flow');
122→    }
123→  }, []);
124→
125→  const handleDisconnect = useCallback(async () => {
126→    if (pollRef.current) { clearInterval(pollRef.current); pollRef.current = null; }
127→    try {
