import { useState, useRef, useEffect, useCallback } from 'react';
import type { Project, GitHubRepo } from '../types';
import { api } from '../api/client';

type Tab = 'github' | 'local';
type GitHubState = 'idle' | 'device_flow' | 'connected';

interface ProjectSetupProps {
  projects: Project[];
  onSelect: (project: Project) => void;
  onCreate: (name: string, path: string) => void;
  onClone: (repoUrl: string) => Promise<void>;
}

export function ProjectSetup({ projects, onSelect, onCreate, onClone }: ProjectSetupProps) {
  const [tab, setTab] = useState<Tab>('github');
  const [name, setName] = useState('');
  const [path, setPath] = useState('');
  const [repoUrl, setRepoUrl] = useState('');
  const [error, setError] = useState('');
  const [cloning, setCloning] = useState(false);

  // GitHub auth state
  const [ghState, setGhState] = useState<GitHubState>('idle');
  const [repos, setRepos] = useState<GitHubRepo[]>([]);
  const [repoSearch, setRepoSearch] = useState('');
  const [selectedRepo, setSelectedRepo] = useState<GitHubRepo | null>(null);
  const [showManualInput, setShowManualInput] = useState(false);
  const [tokenInput, setTokenInput] = useState('');
  const [connectingToken, setConnectingToken] = useState(false);
  const [clientIdConfigured, setClientIdConfigured] = useState(false);
  const [showPatInput, setShowPatInput] = useState(false);

  // Device flow state
  const [deviceUserCode, setDeviceUserCode] = useState('');
  const [deviceVerificationUri, setDeviceVerificationUri] = useState('');
  const pollRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const repoRef = useRef<HTMLInputElement>(null);
  const nameRef = useRef<HTMLInputElement>(null);
  const tokenRef = useRef<HTMLInputElement>(null);

  // Check GitHub auth status on mount
  useEffect(() => {
    api.githubStatus()
      .then((s) => {
        setClientIdConfigured(s.client_id_configured);
        if (s.connected) {
          setGhState('connected');
          api.githubRepos().then(setRepos).catch(console.error);
        }
      })
      .catch(console.error);
  }, []);

  // Cleanup device flow polling on unmount
  useEffect(() => {
    return () => {
      if (pollRef.current) clearInterval(pollRef.current);
    };
  }, []);

  useEffect(() => {
    if (tab === 'github' && showManualInput) repoRef.current?.focus();
    else if (tab === 'github' && ghState === 'idle') tokenRef.current?.focus();
    else if (tab === 'local') nameRef.current?.focus();
  }, [tab, showManualInput, ghState]);

  const handleConnectToken = useCallback(async (e: React.FormEvent) => {
    e.preventDefault();
    if (!tokenInput.trim()) return;
    setError('');
    setConnectingToken(true);
    try {
      await api.githubConnectToken(tokenInput.trim());
      setGhState('connected');
      setTokenInput('');
      const fetchedRepos = await api.githubRepos();
      setRepos(fetchedRepos);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to connect');
    } finally {
      setConnectingToken(false);
    }
  }, [tokenInput]);

  const handleDeviceFlow = useCallback(async () => {
    setError('');
    try {
      const result = await api.githubDeviceCode();
      setDeviceUserCode(result.user_code);
      setDeviceVerificationUri(result.verification_uri);
      setGhState('device_flow');

      // Start polling for token completion
      const interval = Math.max(result.interval, 5) * 1000;
      pollRef.current = setInterval(async () => {
        try {
          const poll = await api.githubPollToken(result.device_code);
          if (poll.status === 'complete') {
            if (pollRef.current) clearInterval(pollRef.current);
            pollRef.current = null;
            setGhState('connected');
            setDeviceUserCode('');
            setDeviceVerificationUri('');
            const fetchedRepos = await api.githubRepos();
            setRepos(fetchedRepos);
          }
        } catch (err) {
          const msg = err instanceof Error ? err.message : String(err);
          if (msg.includes('access_denied') || msg.includes('expired_token')) {
            if (pollRef.current) { clearInterval(pollRef.current); pollRef.current = null; }
            setGhState('idle');
            setDeviceUserCode('');
            setDeviceVerificationUri('');
          }
          // authorization_pending and slow_down are expected -- continue polling
        }
      }, interval);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to start device flow');
    }
  }, []);

  const handleDisconnect = useCallback(async () => {
    if (pollRef.current) { clearInterval(pollRef.current); pollRef.current = null; }
    try {
      await api.githubDisconnect();
    } catch (err) {
      console.error('[github] Disconnect failed:', err);
    }
    // Continue with state cleanup regardless
    setGhState('idle');
    setRepos([]);
    setSelectedRepo(null);
    setRepoSearch('');
    setDeviceUserCode('');
    setDeviceVerificationUri('');
    setShowPatInput(false);
  }, []);

  const handleCloneRepo = async (repo: GitHubRepo) => {
    setError('');
    setCloning(true);
    try {
      await onClone(repo.clone_url);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Clone failed');
    } finally {
      setCloning(false);
    }
  };

  const handleManualClone = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    if (!repoUrl.trim()) return;
    setCloning(true);
    try {
