/// `POST /api/projects/:id/issues` — create a new issue in a project.
///
/// **Request body:**
/// ```json
/// { "title": "Fix bug", "description": "Details...", "column": "backlog" }
/// ```
///
/// `column` defaults to `"backlog"` if omitted.
///
/// **Response:** `201 Created` with the created `Issue` as JSON.
/// Broadcasts an `IssueCreated` WebSocket message.
async fn create_issue(
    State(state): State<SharedState>,
    Path(project_id): Path<i64>,
    Json(req): Json<CreateIssueRequest>,
) -> Result<impl IntoResponse, ApiError> {
    let column = match &req.column {
        Some(c) => IssueColumn::from_str(c).map_err(ApiError::BadRequest)?,
        None => IssueColumn::Backlog,
    };
    let title = req.title;
    let description = req.description.unwrap_or_default();
    let issue = state
        .db
        .call(move |db| db.create_issue(project_id, &title, &description, &column))
        .await
        .map_err(|e| ApiError::Internal(e.to_string()))?;
    broadcast_message(
        &state.ws_tx,
        &WsMessage::IssueCreated {
            issue: issue.clone(),
        },
    );
    Ok((StatusCode::CREATED, Json(issue)))
}

