/// `PATCH /api/issues/:id` — update an issue's title and/or description.
///
/// **Request body:**
/// ```json
/// { "title": "New title", "description": "Updated body" }
/// ```
///
/// All fields are optional; only provided fields are updated.
///
/// **Response:** `200 OK` with the updated `Issue` as JSON.
/// Broadcasts an `IssueUpdated` WebSocket message.
async fn update_issue(
    State(state): State<SharedState>,
    Path(id): Path<i64>,
    Json(req): Json<UpdateIssueRequest>,
) -> Result<impl IntoResponse, ApiError> {
    let title = req.title;
    let description = req.description;
    let priority = req.priority;
    let labels = req.labels;
    let issue = state
        .db
        .call(move |db| {
            db.update_issue(
                id,
                title.as_deref(),
                description.as_deref(),
                priority.as_deref(),
                labels.as_deref(),
            )
        })
        .await
        .map_err(|e| ApiError::Internal(e.to_string()))?;
    broadcast_message(
        &state.ws_tx,
        &WsMessage::IssueUpdated {
            issue: issue.clone(),
        },
    );
    Ok(Json(issue))
}

/// `PATCH /api/issues/:id/move` — move an issue to a different column and position.
///
/// **Request body:**
/// ```json
/// { "column": "in_progress", "position": 0 }
/// ```
///
/// Broadcasts an `IssueMoved` WebSocket message with `from_column`, `to_column`, `position`.
///
/// **Errors:**
/// - `400 Bad Request` if the column name is invalid
async fn move_issue(
    State(state): State<SharedState>,
    Path(id): Path<i64>,
    Json(req): Json<MoveIssueRequest>,
) -> Result<impl IntoResponse, ApiError> {
    let column = IssueColumn::from_str(&req.column).map_err(ApiError::BadRequest)?;
    let position = req.position;
    let (from_column, issue) = state
        .db
        .call(move |db| {
            // Capture the original column before the move for the WsMessage
            let from_column = db
                .get_issue(id)?
                .map(|i| i.column.as_str().to_string())
                .unwrap_or_default();
            let issue = db.move_issue(id, &column, position)?;
            Ok((from_column, issue))
        })
        .await
        .map_err(|e| ApiError::Internal(e.to_string()))?;
    broadcast_message(
        &state.ws_tx,
        &WsMessage::IssueMoved {
            issue_id: id,
            from_column,
            to_column: req.column.clone(),
            position: req.position,
        },
    );
    Ok(Json(issue))
}

/// `DELETE /api/issues/:id` — permanently delete an issue.
///
/// **Response:** `204 No Content` on success.
/// Broadcasts an `IssueDeleted` WebSocket message.
///
/// **Errors:**
/// - `404 Not Found` if the issue does not exist
async fn delete_issue(
    State(state): State<SharedState>,
    Path(id): Path<i64>,
) -> Result<impl IntoResponse, ApiError> {
    let deleted = state
        .db
        .call(move |db| db.delete_issue(id))
        .await
        .map_err(|e| ApiError::Internal(e.to_string()))?;
    match deleted {
        true => {
            broadcast_message(&state.ws_tx, &WsMessage::IssueDeleted { issue_id: id });
            Ok(StatusCode::NO_CONTENT)
        }
        false => Err(ApiError::NotFound(format!("Issue {} not found", id))),
    }
}

/// `POST /api/issues/:id/run` — start a Forge pipeline run for an issue.
///
/// Creates a new `PipelineRun` record then spawns pipeline execution in a background
/// Tokio task. Emits real-time status updates via WebSocket.
///
/// **Response:** `201 Created` with the new `PipelineRun` as JSON.
///
/// **Errors:**
/// - `404 Not Found` if the issue does not exist
/// - `500 Internal Server Error` if the runner fails to start
async fn trigger_pipeline(
    State(state): State<SharedState>,
    Path(issue_id): Path<i64>,
) -> Result<impl IntoResponse, ApiError> {
    let (run, issue) = state
        .db
        .call(move |db| {
            let issue = db
                .get_issue(issue_id)?
                .ok_or_else(|| anyhow::anyhow!("Issue {} not found", issue_id))?;
            let run = db.create_pipeline_run(issue_id)?;
            Ok((run, issue))
        })
        .await
        .map_err(|e| {
            let msg = e.to_string();
            if msg.contains("not found") {
                ApiError::from(FactoryError::IssueNotFound { id: issue_id })
            } else {
                ApiError::Internal(msg)
            }
        })?;

    // Start pipeline execution in a background task
    let run_id = run.id;
    state
        .pipeline_runner
        .start_run(run_id, &issue, state.db.clone(), state.ws_tx.clone())
        .await
        .map_err(|e| ApiError::Internal(e.to_string()))?;

    // Re-fetch the run after start_run (which updates status to Running)
    let updated_run = state
        .db
        .call(move |db| {
            db.get_pipeline_run(run_id)?
                .ok_or_else(|| anyhow::anyhow!("Pipeline run {} not found", run_id))
        })
        .await
        .map_err(|e| ApiError::Internal(e.to_string()))?;

    Ok((StatusCode::CREATED, Json(updated_run)))
}

/// `GET /api/runs/:id` — get the status and details of a pipeline run.
///
/// **Response:** `200 OK` with a `PipelineRun` object as JSON.
///
/// **Errors:**
/// - `404 Not Found` if the run does not exist
async fn get_pipeline_run(
    State(state): State<SharedState>,
    Path(id): Path<i64>,
) -> Result<impl IntoResponse, ApiError> {
    let run = state
        .db
        .call(move |db| db.get_pipeline_run(id))
        .await
        .map_err(|e| ApiError::Internal(e.to_string()))?;
    match run {
        Some(run) => Ok(Json(run)),
        None => Err(ApiError::NotFound(format!("Pipeline run {} not found", id))),
    }
}

/// `POST /api/runs/:id/cancel` — cancel a running pipeline.
///
/// Sends a cancellation signal to the pipeline process and updates the run status in the DB.
///
/// **Response:** `200 OK` with the updated `PipelineRun` as JSON.
///
/// **Errors:**
/// - `500 Internal Server Error` if cancellation fails
async fn cancel_pipeline_run(
    State(state): State<SharedState>,
    Path(id): Path<i64>,
) -> Result<impl IntoResponse, ApiError> {
    // Kill the running process and update DB status
    let run = state
        .pipeline_runner
        .cancel(id, &state.db, &state.ws_tx)
        .await
        .map_err(|e| ApiError::Internal(e.to_string()))?;
    Ok(Json(run))
}

