  1→import { useState, useRef, useEffect, useCallback, useMemo } from 'react';
  2→import { api } from '../api/client';
  3→import type { CliHelpResponse } from '../types';
  4→
  5→interface CommandAutocompleteProps {
  6→  onCommand?: (command: string) => void;
  7→}
  8→
  9→interface SuggestionItem {
 10→  kind: 'cmd' | 'opt';
 11→  label: string;
 12→  description: string;
 13→}
 14→
 15→export default function CommandAutocomplete({ onCommand }: CommandAutocompleteProps) {
 16→  const [input, setInput] = useState('');
 17→  const [helpData, setHelpData] = useState<CliHelpResponse | null>(null);
 18→  const [open, setOpen] = useState(false);
 19→  const [highlightIndex, setHighlightIndex] = useState(0);
 20→
 21→  const containerRef = useRef<HTMLDivElement>(null);
 22→  const inputRef = useRef<HTMLInputElement>(null);
 23→
 24→  // Fetch CLI help data on mount
 25→  useEffect(() => {
 26→    api.cliHelp().then(setHelpData).catch(() => {});
 27→  }, []);
 28→
 29→  // Build flat suggestion list from help data
 30→  const allItems = useMemo<SuggestionItem[]>(() => {
 31→    if (!helpData) return [];
 32→    const cmds: SuggestionItem[] = helpData.commands.map(c => ({
 33→      kind: 'cmd',
 34→      label: c.name,
 35→      description: c.description,
 36→    }));
 37→    const opts: SuggestionItem[] = helpData.options.map(o => ({
 38→      kind: 'opt',
 39→      label: o.flag,
 40→      description: o.description,
 41→    }));
 42→    return [...cmds, ...opts];
 43→  }, [helpData]);
 44→
 45→  // Filter by prefix match
 46→  const filtered = useMemo(() => {
 47→    if (!input) return allItems;
 48→    const lower = input.toLowerCase();
 49→    return allItems.filter(item => item.label.toLowerCase().startsWith(lower));
 50→  }, [allItems, input]);
 51→
 52→  // Ghost text: remaining chars of top match
 53→  const ghostText = useMemo(() => {
 54→    if (!input || filtered.length === 0) return '';
 55→    const top = filtered[0].label;
 56→    if (top.toLowerCase().startsWith(input.toLowerCase())) {
 57→      return top.slice(input.length);
 58→    }
 59→    return '';
 60→  }, [input, filtered]);
 61→
 62→  // Reset highlight when filtered list changes
 63→  useEffect(() => {
 64→    setHighlightIndex(0);
 65→  }, [filtered.length]);
 66→
 67→  // Click outside to close
 68→  useEffect(() => {
 69→    function handleClick(e: MouseEvent) {
 70→      if (containerRef.current && !containerRef.current.contains(e.target as Node)) {
 71→        setOpen(false);
 72→      }
 73→    }
 74→    document.addEventListener('mousedown', handleClick);
 75→    return () => document.removeEventListener('mousedown', handleClick);
 76→  }, []);
 77→
 78→  const selectItem = useCallback((item: SuggestionItem) => {
 79→    setInput(item.label);
 80→    setOpen(false);
 81→    inputRef.current?.focus();
 82→  }, []);
 83→
 84→  const handleKeyDown = (e: React.KeyboardEvent) => {
 85→    if (e.key === 'ArrowDown' && open) {
 86→      e.preventDefault();
 87→      setHighlightIndex(i => (i + 1) % filtered.length);
 88→    } else if (e.key === 'ArrowUp' && open) {
 89→      e.preventDefault();
 90→      setHighlightIndex(i => (i - 1 + filtered.length) % filtered.length);
 91→    } else if (e.key === 'Enter') {
 92→      e.preventDefault();
 93→      if (open && filtered.length > 0) {
 94→        selectItem(filtered[highlightIndex]);
 95→      } else if (input.trim()) {
 96→        onCommand?.(input.trim());
 97→        setInput('');
 98→        setOpen(false);
 99→      }
100→    } else if (e.key === 'Escape') {
101→      setOpen(false);
102→    } else if (e.key === 'Tab' && ghostText) {
103→      e.preventDefault();
104→      setInput(input + ghostText);
105→      setOpen(false);
106→    }
107→  };
108→
109→  return (
110→    <div ref={containerRef} style={{ position: 'relative', flex: 1 }}>
111→      {/* Input + ghost text wrapper */}
112→      <div style={{ position: 'relative' }}>
113→        <input
114→          ref={inputRef}
115→          type="text"
116→          value={input}
117→          onChange={e => {
118→            setInput(e.target.value);
119→            setOpen(true);
120→          }}
121→          onFocus={() => setOpen(true)}
122→          onKeyDown={handleKeyDown}
123→          placeholder="type a command..."
124→          style={{
125→            width: '100%',
126→            background: 'transparent',
127→            border: 'none',
128→            outline: 'none',
129→            color: 'var(--color-text-primary)',
130→            fontFamily: 'inherit',
131→            fontSize: 'inherit',
132→          }}
133→        />
134→        {/* Ghost text overlay */}
135→        {ghostText && (
136→          <span
137→            aria-hidden
138→            style={{
139→              position: 'absolute',
140→              left: 0,
141→              top: 0,
142→              pointerEvents: 'none',
143→              fontFamily: 'inherit',
144→              fontSize: 'inherit',
145→              color: 'var(--color-text-secondary)',
146→              opacity: 0.5,
147→              whiteSpace: 'pre',
148→            }}
149→          >
150→            <span style={{ visibility: 'hidden' }}>{input}</span>
151→            {ghostText}
152→          </span>
153→        )}
154→      </div>
155→
156→      {/* Dropdown */}
157→      {open && filtered.length > 0 && (
158→        <div
159→          style={{
160→            position: 'absolute',
161→            top: '100%',
162→            left: 0,
163→            right: 0,
164→            marginTop: '4px',
165→            backgroundColor: 'var(--color-bg-card)',
166→            border: '1px solid var(--color-border)',
167→            borderRadius: '4px',
168→            maxHeight: '200px',
169→            overflowY: 'auto',
170→            zIndex: 1000,
171→          }}
172→        >
173→          {filtered.map((item, i) => (
174→            <div
175→              key={`${item.kind}-${item.label}`}
176→              onMouseDown={e => {
177→                e.preventDefault();
178→                selectItem(item);
179→              }}
180→              onMouseEnter={() => setHighlightIndex(i)}
181→              style={{
182→                display: 'flex',
183→                alignItems: 'center',
184→                padding: '6px 10px',
